package com.example.lessondesign.controller; import com.example.lessondesign.bean.Course; import com.example.lessondesign.dao.CourseDao; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/courses") public class CourseController { @Autowired private CourseDao courseDao; @GetMapping public ResponseEntity<List<Course>> getAll(){ return ResponseEntity.ok(courseDao.findAll()); } @GetMapping("/{id}") public ResponseEntity<Course> getById(@PathVariable int id){ Course c=courseDao.findById(id); return c!=null?ResponseEntity.ok(c):ResponseEntity.notFound().build(); } }